/**
 * 种族动态世界书（独立脚本，与 `关键字动态世界书` 无关）
 *
 * 蓝灯 / 绿灯 = 世界书条目的 `strategy.type`：
 * - 蓝：`constant`
 * - 绿：`selective`
 *
 * 规则（每种族一条世界书条目，由你逐步在下方 RACE_ENTRIES 里配置）：
 * - 若**顶层聊天输入框草稿**或**最近两条已发送消息**（用户/AI 任意）的正文中，出现该种族任意一个 `matchSubstrings` 子串 → 该条目蓝灯。
 * - 当且仅当：输入框里没有命中、且最近两条消息里**各自**都没有命中 → 该条目绿灯。
 *
 * 仅会修改：名称 `includes(entryNameIncludes)` 的条目；跳过 `enabled === false`；不改动 `vectorized` 条目。
 */

// ========== 小白只改下面这一块：按需追加 `{ entryNameIncludes, matchSubstrings }` ==========

/** 世界书条目名需包含的片段（例如条目「种族-人类」→ 填 `种族-人类`） */
const RACE_ENTRIES: Array<{ entryNameIncludes: string; matchSubstrings: string[] }> = [
  { entryNameIncludes: '种族-提夫林', matchSubstrings: ['提夫林', 'Tiefling'] },
  { entryNameIncludes: '种族-半精灵', matchSubstrings: ['半精灵', 'Half-Elf'] },
  {
    entryNameIncludes: '种族-卓尔·暗精灵',
    matchSubstrings: ['卓尔·暗精灵', '卓尔', '暗精灵', 'Drow'],
  },
  { entryNameIncludes: '种族-龙裔', matchSubstrings: ['龙裔', 'Dragonborn'] },
  { entryNameIncludes: '种族-天使裔', matchSubstrings: ['天使裔', 'Aasimar'] },
  { entryNameIncludes: '种族-高等精灵', matchSubstrings: ['高等精灵', 'High Elf'] },
  { entryNameIncludes: '种族-月精灵', matchSubstrings: ['月精灵', 'Moon Elf'] },
  { entryNameIncludes: '种族-半魅魔', matchSubstrings: ['半魅魔', 'Half-Succubus'] },
  { entryNameIncludes: '种族-天空精灵', matchSubstrings: ['天空精灵', 'Sun Elf'] },
  { entryNameIncludes: '种族-幽冥裔', matchSubstrings: ['幽冥裔', 'Shadar-Kai'] },
  { entryNameIncludes: '种族-人类', matchSubstrings: ['人类', 'Human'] },
];

// ========== 一般不用动 ==========

const DEBOUNCE_MS = 450;
const DRAFT_POLL_MS = 600;

const HIT_TYPE = 'constant' as const;
const MISS_TYPE = 'selective' as const;

/** 设为 true 后重新 build，控制台会打 `[种族世界书]` 日志 */
const DEBUG = false;

const LOG_PREFIX = '[种族世界书]';

const TEXTAREA_SELECTORS =
  '#send_textarea, textarea[name="send_textarea"], textarea#send_textarea, #send_text, textarea[data-testid="send_textarea"], textarea.mes_textarea';

function log(...args: unknown[]): void {
  if (!DEBUG) return;
  console.info(LOG_PREFIX, ...args);
}

function stripScanText(raw: string): string {
  let s = raw;
  s = s.replace(/```[\s\S]*?```/g, ' ');
  s = s.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, ' ');
  return s;
}

function readTopSendTextareaText(): string {
  try {
    const doc = window.top?.document;
    if (!doc) return '';
    const el = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!el) return '';
    return String(el.value ?? '');
  } catch {
    return '';
  }
}

function getLastTwoMessageTexts(): string[] {
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return [];
    const msgs = getChatMessages(`0-${lastId}`);
    const lastTwo = msgs.slice(-2);
    return lastTwo.map(m => stripScanText(m.message ?? '').trim()).filter(Boolean);
  } catch (e) {
    console.warn(LOG_PREFIX, '获取最近消息失败', e);
    return [];
  }
}

function textMatchesRace(text: string, matchSubstrings: string[]): boolean {
  if (!text) return false;
  for (const k of matchSubstrings) {
    const s = k?.trim();
    if (s && text.includes(s)) return true;
  }
  return false;
}

/** 蓝灯：草稿或最近两条任一楼层命中 */
function raceShouldHit(entry: (typeof RACE_ENTRIES)[number]): boolean {
  const draft = stripScanText(readTopSendTextareaText());
  if (textMatchesRace(draft, entry.matchSubstrings)) {
    log('命中: 输入框', entry.entryNameIncludes);
    return true;
  }
  for (const body of getLastTwoMessageTexts()) {
    if (textMatchesRace(body, entry.matchSubstrings)) {
      log('命中: 已发消息', entry.entryNameIncludes, body.slice(0, 80));
      return true;
    }
  }
  return false;
}

function getPrimaryWorldbookName(): string | null {
  try {
    const { primary } = getCharWorldbookNames('current');
    const n = primary?.trim();
    return n ? n : null;
  } catch {
    return null;
  }
}

function findRaceConfigForEntryName(entryName: string): (typeof RACE_ENTRIES)[number] | null {
  for (const r of RACE_ENTRIES) {
    if (r.entryNameIncludes && entryName.includes(r.entryNameIncludes)) return r;
  }
  return null;
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;
let lastDraftSnapshot = '';

function scheduleSync(): void {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    debounceTimer = null;
    void errorCatched(syncRaceWorldbook)();
  }, DEBOUNCE_MS);
}

async function syncRaceWorldbook(): Promise<void> {
  const wbName = getPrimaryWorldbookName();
  if (!wbName) {
    console.warn(LOG_PREFIX, '当前角色未绑定主世界书 primary，已跳过');
    return;
  }

  await updateWorldbookWith(wbName, entries => {
    for (const entry of entries) {
      if (!entry.enabled) continue;
      const name = entry?.name ?? '';
      if (!name) continue;

      const race = findRaceConfigForEntryName(name);
      if (!race) continue;

      if (entry.strategy?.type === 'vectorized') continue;

      const nextType = raceShouldHit(race) ? HIT_TYPE : MISS_TYPE;
      if (entry.strategy.type === nextType) continue;

      entry.strategy = { ...entry.strategy, type: nextType };
      log(`条目 strategy.type: ${name} → ${nextType}`);
    }
    return entries;
  });
}

function bindTopSendTextareaHooks(): void {
  try {
    const doc = window.top?.document;
    if (!doc) return;
    const textarea = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!textarea) return;

    const mark = '__raceDynamicWbBound__';
    if ((textarea as any)[mark]) return;
    (textarea as any)[mark] = true;

    const onChange = () => scheduleSync();
    textarea.addEventListener('input', onChange);
    textarea.addEventListener('paste', onChange);
    textarea.addEventListener('cut', onChange);
    textarea.addEventListener('keydown', (ev: KeyboardEvent) => {
      if (ev.key !== 'Enter') return;
      if (ev.shiftKey || ev.ctrlKey || ev.altKey) return;
      onChange();
    });
    onChange();
  } catch {
    /* ignore */
  }
}

function startDraftPoll(): void {
  const k = '__raceDynamicWbDraftPoll__';
  if ((globalThis as any)[k]) return;
  (globalThis as any)[k] = setInterval(() => {
    const snap = readTopSendTextareaText();
    if (snap === lastDraftSnapshot) return;
    lastDraftSnapshot = snap;
    scheduleSync();
  }, DRAFT_POLL_MS);
}

function exposeDebugHelpers(): void {
  const g = globalThis as any;
  g.__raceWbDump = () => {
    const o = {
      primary: getPrimaryWorldbookName(),
      draftPreview: readTopSendTextareaText().slice(0, 120),
      lastTwo: getLastTwoMessageTexts().map(t => t.slice(0, 120)),
      hits: RACE_ENTRIES.map(r => ({
        entry: r.entryNameIncludes,
        hit: raceShouldHit(r),
      })),
    };
    console.info(LOG_PREFIX, '__raceWbDump', o);
    return o;
  };
  try {
    if (window.top && window.top !== window) (window.top as any).__raceWbDump = g.__raceWbDump;
  } catch {
    /* cross-origin */
  }
}

$(() => {
  errorCatched(() => {
    exposeDebugHelpers();
    bindTopSendTextareaHooks();
    startDraftPoll();

    void syncRaceWorldbook();

    eventOn(tavern_events.MESSAGE_SENT, scheduleSync);
    eventOn(tavern_events.MESSAGE_RECEIVED, scheduleSync);
    eventOn(tavern_events.MESSAGE_UPDATED, scheduleSync);
    eventOn(tavern_events.CHAT_CHANGED, scheduleSync);
    eventOn(tavern_events.CHARACTER_PAGE_LOADED, scheduleSync);

    $(window).on('pagehide', () => {
      if (debounceTimer) {
        clearTimeout(debounceTimer);
        debounceTimer = null;
      }
    });

    console.info(LOG_PREFIX, '已加载；种族规则数:', RACE_ENTRIES.length);
  })();
});
